
 
COMMIT;

 
COMMIT;

-- Deposits (300)
SELECT
    NULL,
    (SELECT AccountID FROM (
        SELECT AccountID FROM Accounts WHERE Status != 'Closed' ORDER BY DBMS_RANDOM.VALUE
     ) WHERE ROWNUM = 1),
    ROUND(DBMS_RANDOM.VALUE(100, 60000), 2),
    'Deposit',
    ADD_MONTHS(TRUNC(SYSDATE), -TRUNC(DBMS_RANDOM.VALUE(0,12))) - TRUNC(DBMS_RANDOM.VALUE(0,28))
FROM DUAL
CONNECT BY LEVEL <= 300;
 
-- Withdrawals (225)
SELECT
    (SELECT AccountID FROM (
        SELECT AccountID FROM Accounts WHERE Status != 'Closed' ORDER BY DBMS_RANDOM.VALUE
     ) WHERE ROWNUM = 1),
    NULL,
    ROUND(DBMS_RANDOM.VALUE(100, 60000), 2),
    'Withdrawal',
    ADD_MONTHS(TRUNC(SYSDATE), -TRUNC(DBMS_RANDOM.VALUE(0,12))) - TRUNC(DBMS_RANDOM.VALUE(0,28))
FROM DUAL
CONNECT BY LEVEL <= 225;
 
-- Transfers (225)
SELECT
    from_acc,
    to_acc,
    ROUND(DBMS_RANDOM.VALUE(100, 60000), 2),
    'Transfer',
    ADD_MONTHS(TRUNC(SYSDATE), -TRUNC(DBMS_RANDOM.VALUE(0,12))) - TRUNC(DBMS_RANDOM.VALUE(0,28))
FROM (
    SELECT
        (SELECT AccountID FROM (
            SELECT AccountID FROM Accounts WHERE Status != 'Closed' ORDER BY DBMS_RANDOM.VALUE
         ) WHERE ROWNUM = 1) AS from_acc,
        (SELECT AccountID FROM (
            SELECT AccountID FROM Accounts WHERE Status != 'Closed' ORDER BY DBMS_RANDOM.VALUE
         ) WHERE ROWNUM = 1) AS to_acc
    FROM DUAL
    CONNECT BY LEVEL <= 225
)
WHERE from_acc != to_acc;
 
COMMIT;

-- Verify no orphaned references (should return 0 rows)
SELECT * FROM Transactions t
WHERE (t.FromAccountID IS NOT NULL AND t.FromAccountID NOT IN (SELECT AccountID FROM Accounts))
   OR (t.ToAccountID IS NOT NULL AND t.ToAccountID NOT IN (SELECT AccountID FROM Accounts));